  color: var(--text-primary);
}

/* Highlight matching events when search is active */
.timeline-event.search-highlight {
  border-color: var(--accent);
  box-shadow: 0 0 0 1px rgba(88, 166, 255, 0.3);
}

.timeline-event.search-dimmed {
  opacity: 0.3;
  pointer-events: none;
}

.search-match-text {
  background: rgba(88, 166, 255, 0.25);
  color: var(--accent-hover);
  border-radius: 2px;
  padding: 0 2px;
}

@media (max-width: 768px) {
  .search-row {
    flex-direction: column;
  }
  .search-select {
    width: 100%;
    min-width: unset;
  }
  .advanced-filters {
    flex-direction: column;
    gap: 8px;
  }
  .filter-number-input {
    width: 100%;
  }
}

/* ── Alert Rules ─────────────────────────────────────────────────────── */

.btn-alert-header {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 6px 14px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 6px;
